<template>
  <div class="bookmarkCard">
    <article>
      <h3>{{ title }}</h3>
      <div class="list">
        <a
          v-for="(item, i) in finalBookmarks"
          :key="i"
          :title="item.name"
          :href="item.url"
        >{{ item.name }}</a>
      </div>
      <button v-if="bookmarks.length > 9" @click="showAll()">
        <span
          class="down"
          :class="{transtoUp: isCollapse === false}"
        >&gt;</span>
      </button>
    </article>
  </div>
</template>

<script>
export default {
  props: {
    title: {
      type: String,
      required: true,
      default: 'Title'
    },
    bookmarks: {
      type: Array,
      required: true,
      default() { return [
        {name: 'name', intro: 'intro', url: ''}
      ]}
    },
  },

  data() { return {
    isCollapse: true
  }},

  computed: {
    finalBookmarks() {
      if (this.isCollapse === true && this.bookmarks.length > 9) {
        return this.bookmarks.slice(0, 9);
      } else {
        return this.bookmarks;
      }
    }
  },

  methods: {
    showAll() {
      this.isCollapse = !this.isCollapse;
    }
  }

}
</script>

<style lang="scss" scoped>
@import '@/common/_public.scss';

div.bookmarkCard {
  box-sizing: border-box;
  width: 100%;
  max-width: 400px;
  @include padding(0.5, 1);
  border: 1px solid $shadow;
  border-radius: ($sz-normal / 4);
  margin: 0 auto;
  margin-bottom: ($sz-normal * 2);

  h3 {
    box-sizing: border-box;
    color: $title;
    padding-bottom: ($sz-normal * 0.5);
    border-bottom: 1px solid $shadow;
    margin-bottom: ($sz-normal * 0.5);
  }
  a {
    display: block;
    box-sizing: border-box;
    width: 100%;
    overflow: hidden;
    color: $content;
    white-space: pre;
    text-overflow: ellipsis;
    text-decoration: none;
    padding-right: $sz-normal;
    @include margin(0.25, 0);
  }
  button {
    display: block;
    cursor: pointer;
    box-sizing: border-box;
    width: 100%;
    background: transparent;
    @include padding(0.5, 0);
    border: 0;
    outline: 0;
  }
  span.down {
    display: inline-block;
    transform-origin: center 55%;
    transform: rotate(90deg) scale(0.9, 1.5);
  }
  span.transtoUp {
    transform: rotate(270deg) scale(0.9, 1.5);
    transition: transform 400ms ease;
  }
}

div.list {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(100px, 1fr));
}

</style>